// Validate GitLab webhook token and extract MR data
const headers = $input.first().json.headers;
const body = $input.first().json.body;

// --- Token validation ---
const receivedToken = headers['x-gitlab-token'] || headers['X-Gitlab-Token'] || '';
const expectedToken = $env.GITLAB_WEBHOOK_SECRET;

if (!receivedToken || receivedToken !== expectedToken) {
  return [{ json: {
    valid: false,
    reason: 'Invalid or missing X-Gitlab-Token header',
    timestamp: new Date().toISOString()
  }}];
}

// --- Event type validation ---
const eventType = headers['x-gitlab-event'] || headers['X-Gitlab-Event'] || '';
if (eventType !== 'Merge Request Hook') {
  return [{ json: {
    valid: false,
    reason: `Unexpected event type: ${eventType}`,
    timestamp: new Date().toISOString()
  }}];
}

// --- MR state validation ---
const attrs = body.object_attributes || {};
if (attrs.state !== 'merged' || attrs.action !== 'merge') {
  return [{ json: {
    valid: false,
    reason: `MR not merged (state=${attrs.state}, action=${attrs.action})`,
    timestamp: new Date().toISOString()
  }}];
}

// --- Extract fields ---
const project = body.project || {};
const user = body.user || {};

return [{ json: {
  valid: true,
  target_branch: attrs.target_branch,
  source_branch: attrs.source_branch,
  merge_commit_sha: attrs.merge_commit_sha || attrs.last_commit?.id || 'unknown',
  mr_title: attrs.title,
  mr_iid: attrs.iid,
  mr_url: attrs.url,
  project_name: project.name,
  project_path: project.path_with_namespace,
  project_git_url: project.git_ssh_url || project.git_http_url,
  project_id: project.id,
  author: user.username || user.name || 'unknown',
  timestamp: new Date().toISOString()
}}];

// Build git sync commands for the VPS git-bridge
const data = $json;
const project = data.project_name;
const branch = data.target_branch;
const gitlabUrl = data.project_git_url;
const bridgeBase = '/docker/git-bridge';
const repoDir = `${bridgeBase}/${project}`;

// First-time setup: clone bare + add github remote
// Subsequent: fetch from gitlab, push to github
const setupCmd = [
  `mkdir -p ${bridgeBase}`,
  `if [ ! -d "${repoDir}" ]; then`,
  `  git clone --bare ${gitlabUrl} ${repoDir}`,
  `  cd ${repoDir}`,
  `  git remote add github \"https://\${GITHUB_TOKEN}@github.com/\${GITHUB_OWNER}/${project}.git\"`,
  `else`,
  `  cd ${repoDir}`,
  `fi`
].join('\n');

const syncCmd = [
  `cd ${repoDir}`,
  `git fetch origin`,
  `git push github refs/heads/${branch}:refs/heads/${branch} --force`
].join(' && ');

const fullCmd = `${setupCmd}\n${syncCmd}`;

return [{ json: {
  ...data,
  bridge_dir: repoDir,
  sync_command: fullCmd,
  sync_branch: branch,
  sync_description: `Sync ${project}/${branch} (${data.merge_commit_sha.substring(0, 8)}) GitLab -> GitHub`
}}];

// Execute git sync via child_process
// Requires n8n to have filesystem access to /docker/git-bridge (volume mount)
const { execSync } = require('child_process');
const data = $json;

let result = { success: false, stdout: '', stderr: '', exitCode: -1 };

try {
  // Set env vars for the git commands
  const env = {
    ...process.env,
    GITHUB_TOKEN: $env.GITHUB_TOKEN,
    GITHUB_OWNER: $env.GITHUB_OWNER,
    GIT_TERMINAL_PROMPT: '0'
  };

  const stdout = execSync(data.sync_command, {
    encoding: 'utf8',
    timeout: 60000,
    env,
    shell: '/bin/bash'
  });

  result = {
    success: true,
    stdout: stdout.trim(),
    stderr: '',
    exitCode: 0
  };
} catch (err) {
  result = {
    success: false,
    stdout: (err.stdout || '').trim(),
    stderr: (err.stderr || err.message || '').trim(),
    exitCode: err.status || 1
  };
}

return [{ json: {
  ...data,
  sync_result: result,
  completed_at: new Date().toISOString()
}}];

// Return webhook response for success
return [{ json: {
  status: 'ok',
  message: `Synced ${$json.project_name}/${$json.sync_branch} to GitHub`,
  sha: $json.merge_commit_sha
}}];

// Return webhook response for failure
return [{ json: {
  status: 'error',
  message: `Sync failed for ${$json.project_name}/${$json.sync_branch}`,
  error: $json.sync_result.stderr
}}];

// Rejected: invalid token, wrong event, or non-protected branch
return [{ json: {
  status: 'ignored',
  reason: $json.reason || `Branch '${$json.target_branch || 'unknown'}' not in protected list`,
  timestamp: new Date().toISOString()
}}];
